const AYAT = [{"s": 1, "a": 1, "sn": "Al-Fatihah", "sar": "الفاتحة", "rev": "Meccan", "ar": "بِسْمِ اللَّهِ الرَّحْمَٰنِ الرَّحِيمِ", "tr": "Bismi Allāhi ar-raḥmāni ar-raḥīm", "en": "In the name of Allah, the Entirely Merciful, the Especially Merciful.", "th": ["mercy", "tawheed"]}, {"s": 1, "a": 2, "sn": "Al-Fatihah", "sar": "الفاتحة", "rev": "Meccan", "ar": "الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ", "tr": "Al-ḥamdu lillāhi rabbi al-'ālamīn", "en": "All praise is due to Allah, Lord of the worlds.", "th": ["gratitude", "tawheed"]}, {"s": 1, "a": 5, "sn": "Al-Fatihah", "sar": "الفاتحة", "rev": "Meccan", "ar": "إِيَّاكَ نَعْبُدُ وَإِيَّاكَ نَسْتَعِينُ", "tr": "Iyyāka na'budu wa-iyyāka nasta'īn", "en": "It is You we worship and You we ask for help.", "th": ["tawheed", "dua"]}, {"s": 1, "a": 6, "sn": "Al-Fatihah", "sar": "الفاتحة", "rev": "Meccan", "ar": "اهْدِنَا الصِّرَاطَ الْمُسْتَقِيمَ", "tr": "Ihdinā aṣ-ṣirāṭa al-mustaqīm", "en": "Guide us to the straight path.", "th": ["guidance", "dua"]}, {"s": 2, "a": 45, "sn": "Al-Baqarah", "sar": "البقرة", "rev": "Medinan", "ar": "وَاسْتَعِينُوا بِالصَّبْرِ وَالصَّلَاةِ", "tr": "Wasta'īnū bi-ṣ-ṣabri wa-ṣ-ṣalāh", "en": "And seek help through patience and prayer.", "th": ["patience"]}, {"s": 2, "a": 152, "sn": "Al-Baqarah", "sar": "البقرة", "rev": "Medinan", "ar": "فَاذْكُرُونِي أَذْكُرْكُمْ وَاشْكُرُوا لِي وَلَا تَكْفُرُونِ", "tr": "Fadhkurūnī adhkurkum", "en": "So remember Me; I will remember you. And be grateful to Me and do not deny Me.", "th": ["dhikr", "gratitude"]}, {"s": 2, "a": 155, "sn": "Al-Baqarah", "sar": "البقرة", "rev": "Medinan", "ar": "وَلَنَبْلُوَنَّكُم بِشَيْءٍ مِّنَ الْخَوْفِ وَالْجُوعِ", "tr": "Wa-lanabluwannakum", "en": "And We will surely test you with something of fear and hunger... but give good tidings to the patient.", "th": ["patience"]}, {"s": 2, "a": 156, "sn": "Al-Baqarah", "sar": "البقرة", "rev": "Medinan", "ar": "الَّذِينَ إِذَا أَصَابَتْهُم مُّصِيبَةٌ قَالُوا إِنَّا لِلَّهِ وَإِنَّا إِلَيْهِ رَاجِعُونَ", "tr": "Innā lillāhi wa-innā ilayhi rāji'ūn", "en": "Who, when disaster strikes them, say: Indeed we belong to Allah, and indeed to Him we will return.", "th": ["patience"]}, {"s": 2, "a": 186, "sn": "Al-Baqarah", "sar": "البقرة", "rev": "Medinan", "ar": "وَإِذَا سَأَلَكَ عِبَادِي عَنِّي فَإِنِّي قَرِيبٌ", "tr": "Wa-idhā sa'alaka", "en": "And when My servants ask you concerning Me — indeed I am near. I respond to the invocation of the supplicant when he calls upon Me.", "th": ["dua"]}, {"s": 2, "a": 201, "sn": "Al-Baqarah", "sar": "البقرة", "rev": "Medinan", "ar": "رَبَّنَا آتِنَا فِي الدُّنْيَا حَسَنَةً وَفِي الْآخِرَةِ حَسَنَةً", "tr": "Rabbanā ātinā", "en": "Our Lord, give us in this world that which is good and in the Hereafter that which is good and protect us from the Fire.", "th": ["dua"]}, {"s": 2, "a": 255, "sn": "Al-Baqarah", "sar": "البقرة", "rev": "Medinan", "ar": "اللَّهُ لَا إِلَٰهَ إِلَّا هُوَ الْحَيُّ الْقَيُّومُ", "tr": "Ayat al-Kursi", "en": "Allah — there is no deity except Him, the Ever-Living, the Sustainer of existence.", "th": ["tawheed"]}, {"s": 2, "a": 286, "sn": "Al-Baqarah", "sar": "البقرة", "rev": "Medinan", "ar": "لَا يُكَلِّفُ اللَّهُ نَفْسًا إِلَّا وُسْعَهَا", "tr": "Lā yukalliful-lāhu", "en": "Allah does not burden a soul beyond that it can bear.", "th": ["patience", "strength"]}, {"s": 3, "a": 139, "sn": "Ali Imran", "sar": "آل عمران", "rev": "Medinan", "ar": "وَلَا تَهِنُوا وَلَا تَحْزَنُوا وَأَنتُمُ الْأَعْلَوْنَ", "tr": "Walā tahinū", "en": "So do not weaken and do not grieve, and you will be superior if you are believers.", "th": ["strength"]}, {"s": 3, "a": 173, "sn": "Ali Imran", "sar": "آل عمران", "rev": "Medinan", "ar": "حَسْبُنَا اللَّهُ وَنِعْمَ الْوَكِيلُ", "tr": "Ḥasbunallāhu wa ni'mal-wakīl", "en": "Sufficient for us is Allah, and He is the best Disposer of affairs.", "th": ["tawakkul"]}, {"s": 7, "a": 23, "sn": "Al-Araf", "sar": "الأعراف", "rev": "Meccan", "ar": "رَبَّنَا ظَلَمْنَا أَنفُسَنَا", "tr": "Rabbanā ẓalamnā", "en": "Our Lord, we have wronged ourselves, and if You do not forgive us and have mercy upon us, we will surely be among the losers.", "th": ["repentance"]}, {"s": 13, "a": 28, "sn": "Ar-Rad", "sar": "الرعد", "rev": "Medinan", "ar": "أَلَا بِذِكْرِ اللَّهِ تَطْمَئِنُّ الْقُلُوبُ", "tr": "Alā bi-dhikri Allāhi", "en": "Unquestionably, by the remembrance of Allah hearts are assured.", "th": ["peace", "dhikr"]}, {"s": 14, "a": 7, "sn": "Ibrahim", "sar": "إبراهيم", "rev": "Meccan", "ar": "لَئِن شَكَرْتُمْ لَأَزِيدَنَّكُمْ", "tr": "La'in shakartum", "en": "If you are grateful, I will surely increase you in favor.", "th": ["gratitude"]}, {"s": 16, "a": 97, "sn": "An-Nahl", "sar": "النحل", "rev": "Meccan", "ar": "مَنْ عَمِلَ صَالِحًا مِّن ذَكَرٍ أَوْ أُنثَىٰ وَهُوَ مُؤْمِنٌ فَلَنُحْيِيَنَّهُ حَيَاةً طَيِّبَةً", "tr": "Man 'amila ṣāliḥan", "en": "Whoever does righteousness, whether male or female, while he is a believer — We will surely cause him to live a good life.", "th": ["righteousness"]}, {"s": 17, "a": 80, "sn": "Al-Isra", "sar": "الإسراء", "rev": "Meccan", "ar": "رَّبِّ أَدْخِلْنِي مُدْخَلَ صِدْقٍ", "tr": "Rabbi adkhilnī", "en": "My Lord, cause me to enter a truthful entrance and to exit a truthful exit.", "th": ["dua"]}, {"s": 18, "a": 10, "sn": "Al-Kahf", "sar": "الكهف", "rev": "Meccan", "ar": "رَبَّنَا آتِنَا مِن لَّدُنكَ رَحْمَةً", "tr": "Rabbanā ātinā min ladunka", "en": "Our Lord, grant us from Yourself mercy and prepare for us from our affair right guidance.", "th": ["dua", "mercy"]}, {"s": 20, "a": 25, "sn": "Ta-Ha", "sar": "طه", "rev": "Meccan", "ar": "رَبِّ اشْرَحْ لِي صَدْرِي وَيَسِّرْ لِي أَمْرِي", "tr": "Rabbi ashraḥ", "en": "My Lord, expand for me my breast and ease for me my task.", "th": ["dua"]}, {"s": 21, "a": 87, "sn": "Al-Anbiya", "sar": "الأنبياء", "rev": "Meccan", "ar": "لَّا إِلَٰهَ إِلَّا أَنتَ سُبْحَانَكَ إِنِّي كُنتُ مِنَ الظَّالِمِينَ", "tr": "Lā ilāha illā anta", "en": "There is no deity except You; exalted are You. Indeed, I have been of the wrongdoers.", "th": ["dua", "repentance"]}, {"s": 21, "a": 107, "sn": "Al-Anbiya", "sar": "الأنبياء", "rev": "Meccan", "ar": "وَمَا أَرْسَلْنَاكَ إِلَّا رَحْمَةً لِّلْعَالَمِينَ", "tr": "Wa-mā arsalnāka", "en": "And We have not sent you, except as a mercy to the worlds.", "th": ["mercy", "prophet"]}, {"s": 24, "a": 35, "sn": "An-Nur", "sar": "النور", "rev": "Medinan", "ar": "اللَّهُ نُورُ السَّمَاوَاتِ وَالْأَرْضِ", "tr": "Allāhu nūru", "en": "Allah is the Light of the heavens and the earth.", "th": ["light"]}, {"s": 33, "a": 41, "sn": "Al-Ahzab", "sar": "الأحزاب", "rev": "Medinan", "ar": "يَا أَيُّهَا الَّذِينَ آمَنُوا اذْكُرُوا اللَّهَ ذِكْرًا كَثِيرًا", "tr": "Udhkurū Allāha", "en": "O you who have believed, remember Allah with much remembrance.", "th": ["dhikr"]}, {"s": 39, "a": 53, "sn": "Az-Zumar", "sar": "الزمر", "rev": "Meccan", "ar": "قُلْ يَا عِبَادِيَ الَّذِينَ أَسْرَفُوا عَلَىٰ أَنفُسِهِمْ لَا تَقْنَطُوا مِن رَّحْمَةِ اللَّهِ", "tr": "Lā taqnaṭū", "en": "Say, O My servants who have transgressed against themselves, do not despair of the mercy of Allah. Indeed, Allah forgives all sins.", "th": ["forgiveness"]}, {"s": 40, "a": 60, "sn": "Ghafir", "sar": "غافر", "rev": "Meccan", "ar": "ادْعُونِي أَسْتَجِبْ لَكُمْ", "tr": "Ud'ūnī astajib lakum", "en": "Call upon Me; I will respond to you.", "th": ["dua"]}, {"s": 49, "a": 13, "sn": "Al-Hujurat", "sar": "الحجرات", "rev": "Medinan", "ar": "إِنَّ أَكْرَمَكُمْ عِندَ اللَّهِ أَتْقَاكُمْ", "tr": "Inna akramakum", "en": "Indeed, the most noble of you in the sight of Allah is the most righteous of you.", "th": ["righteousness", "brotherhood"]}, {"s": 50, "a": 16, "sn": "Qaf", "sar": "ق", "rev": "Meccan", "ar": "وَنَحْنُ أَقْرَبُ إِلَيْهِ مِنْ حَبْلِ الْوَرِيدِ", "tr": "Wa-naḥnu aqrabu", "en": "And We are closer to him than his jugular vein.", "th": ["love"]}, {"s": 55, "a": 13, "sn": "Ar-Rahman", "sar": "الرحمن", "rev": "Medinan", "ar": "فَبِأَيِّ آلَاءِ رَبِّكُمَا تُكَذِّبَانِ", "tr": "Fabi-ayyi ālā'i", "en": "So which of the favors of your Lord would you deny?", "th": ["gratitude"]}, {"s": 57, "a": 3, "sn": "Al-Hadid", "sar": "الحديد", "rev": "Medinan", "ar": "هُوَ الْأَوَّلُ وَالْآخِرُ وَالظَّاهِرُ وَالْبَاطِنُ", "tr": "Huwa al-awwalu", "en": "He is the First and the Last, the Apparent and the Hidden, and He is Knowing of all things.", "th": ["tawheed"]}, {"s": 65, "a": 3, "sn": "At-Talaq", "sar": "الطلاق", "rev": "Medinan", "ar": "وَمَن يَتَوَكَّلْ عَلَى اللَّهِ فَهُوَ حَسْبُهُ", "tr": "Wa man yatawakkal", "en": "And whoever relies upon Allah — then He is sufficient for him.", "th": ["tawakkul"]}, {"s": 65, "a": 7, "sn": "At-Talaq", "sar": "الطلاق", "rev": "Medinan", "ar": "سَيَجْعَلُ اللَّهُ بَعْدَ عُسْرٍ يُسْرًا", "tr": "Sa-yaj'alu Allāhu", "en": "Allah will bring about, after hardship, ease.", "th": ["hope"]}, {"s": 67, "a": 1, "sn": "Al-Mulk", "sar": "الملك", "rev": "Meccan", "ar": "تَبَارَكَ الَّذِي بِيَدِهِ الْمُلْكُ", "tr": "Tabāraka alladhī", "en": "Blessed is He in whose hand is dominion, and He is over all things competent.", "th": ["tawheed"]}, {"s": 93, "a": 3, "sn": "Ad-Duha", "sar": "الضحى", "rev": "Meccan", "ar": "مَا وَدَّعَكَ رَبُّكَ وَمَا قَلَىٰ", "tr": "Mā wadda'aka", "en": "Your Lord has not taken leave of you, nor has He detested you.", "th": ["hope", "love"]}, {"s": 94, "a": 5, "sn": "Ash-Sharh", "sar": "الشرح", "rev": "Meccan", "ar": "فَإِنَّ مَعَ الْعُسْرِ يُسْرًا", "tr": "Fa-inna ma'a al-'usri yusrā", "en": "For indeed, with hardship will be ease.", "th": ["hope"]}, {"s": 94, "a": 6, "sn": "Ash-Sharh", "sar": "الشرح", "rev": "Meccan", "ar": "إِنَّ مَعَ الْعُسْرِ يُسْرًا", "tr": "Inna ma'a al-'usri yusrā", "en": "Indeed, with hardship will be ease.", "th": ["hope"]}, {"s": 112, "a": 1, "sn": "Al-Ikhlas", "sar": "الإخلاص", "rev": "Meccan", "ar": "قُلْ هُوَ اللَّهُ أَحَدٌ", "tr": "Qul huwa Allāhu aḥad", "en": "Say: He is Allah, the One.", "th": ["tawheed"]}, {"s": 112, "a": 2, "sn": "Al-Ikhlas", "sar": "الإخلاص", "rev": "Meccan", "ar": "اللَّهُ الصَّمَدُ", "tr": "Allāhu aṣ-ṣamad", "en": "Allah, the Eternal Refuge.", "th": ["tawheed"]}, {"s": 113, "a": 1, "sn": "Al-Falaq", "sar": "الفلق", "rev": "Meccan", "ar": "قُلْ أَعُوذُ بِرَبِّ الْفَلَقِ", "tr": "Qul a'ūdhu", "en": "Say: I seek refuge in the Lord of daybreak.", "th": ["protection"]}, {"s": 114, "a": 1, "sn": "An-Nas", "sar": "الناس", "rev": "Meccan", "ar": "قُلْ أَعُوذُ بِرَبِّ النَّاسِ", "tr": "Qul a'ūdhu", "en": "Say: I seek refuge in the Lord of mankind.", "th": ["protection"]}];
const HADITH = [{"ar": "إِنَّمَا الْأَعْمَالُ بِالنِّيَّاتِ", "en": "Actions are but by intentions, and every man shall have only that which he intended.", "narr": "Umar ibn al-Khattab", "src": "Bukhari & Muslim", "auth": "Sahih", "cat": "Intention", "num": 1}, {"ar": "مِنْ حُسْنِ إِسْلَامِ الْمَرْءِ تَرْكُهُ مَا لَا يَعْنِيهِ", "en": "Part of the excellence of a person's Islam is their leaving what does not concern them.", "narr": "Abu Hurairah", "src": "Tirmidhi", "auth": "Hasan", "cat": "Character", "num": 12}, {"ar": "لَا يُؤْمِنُ أَحَدُكُمْ حَتَّى يُحِبَّ لِأَخِيهِ مَا يُحِبُّ لِنَفْسِهِ", "en": "None of you truly believes until he loves for his brother what he loves for himself.", "narr": "Anas ibn Malik", "src": "Bukhari & Muslim", "auth": "Sahih", "cat": "Brotherhood", "num": 13}, {"ar": "مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيَقُلْ خَيْرًا أَوْ لِيَصْمُتْ", "en": "Whoever believes in Allah and the Last Day, let him speak good or remain silent.", "narr": "Abu Hurairah", "src": "Bukhari & Muslim", "auth": "Sahih", "cat": "Speech", "num": 15}, {"ar": "لَا تَغْضَبْ", "en": "Do not become angry.", "narr": "Abu Hurairah", "src": "Bukhari", "auth": "Sahih", "cat": "Character", "num": 16}, {"ar": "الدِّينُ النَّصِيحَةُ", "en": "The religion is sincere advice and good counsel.", "narr": "Tamim al-Dari", "src": "Muslim", "auth": "Sahih", "cat": "Character", "num": 7}, {"ar": "مَنْ رَأَى مِنْكُمْ مُنْكَرًا فَلْيُغَيِّرْهُ بِيَدِهِ", "en": "Whoever of you sees an evil, let him change it with his hand; if he is unable, then with his tongue; if unable, then with his heart — and that is the weakest of faith.", "narr": "Abu Sa'id al-Khudri", "src": "Muslim", "auth": "Sahih", "cat": "Character", "num": 34}, {"ar": "مَنْ حَسَنَ إِسْلَامُ الْمَرْءِ", "en": "When a servant embraces Islam perfectly, every good deed is multiplied from ten to seven hundred times, and each bad deed is recorded as one.", "narr": "Abu Sa'id al-Khudri", "src": "Bukhari", "auth": "Sahih", "cat": "Rewards"}, {"ar": "لِكُلِّ امْرِئٍ مَا نَوَى", "en": "Every person gets what they intend.", "narr": "Umar", "src": "Bukhari & Muslim", "auth": "Sahih", "cat": "Intention"}, {"ar": "الطُّهُورُ شَطْرُ الْإِيمَانِ", "en": "Cleanliness is half of faith.", "narr": "Abu Malik al-Ash'ari", "src": "Muslim", "auth": "Sahih", "cat": "Worship"}, {"ar": "الْمُسْلِمُ مَنْ سَلِمَ الْمُسْلِمُونَ مِنْ لِسَانِهِ وَيَدِهِ", "en": "A Muslim is the one from whose tongue and hand other Muslims are safe.", "narr": "Abdullah ibn Amr", "src": "Bukhari", "auth": "Sahih", "cat": "Character"}, {"ar": "الرَّاحِمُونَ يَرْحَمُهُمُ الرَّحْمَنُ", "en": "The merciful are shown mercy by the Most Merciful. Be merciful to those on earth, and the One in the heavens will be merciful to you.", "narr": "Abdullah ibn Amr", "src": "Tirmidhi, Abu Dawud", "auth": "Sahih", "cat": "Mercy"}, {"ar": "مَنْ لَا يَشْكُرِ النَّاسَ لَا يَشْكُرِ اللَّهَ", "en": "He who does not thank people, does not thank Allah.", "narr": "Abu Hurairah", "src": "Tirmidhi, Abu Dawud", "auth": "Sahih", "cat": "Gratitude"}, {"ar": "تَبَسُّمُكَ فِي وَجْهِ أَخِيكَ لَكَ صَدَقَةٌ", "en": "Your smile at your brother's face is charity for you.", "narr": "Abu Dharr", "src": "Tirmidhi", "auth": "Sahih", "cat": "Character"}, {"ar": "إِنَّ اللَّهَ جَمِيلٌ يُحِبُّ الْجَمَالَ", "en": "Indeed Allah is Beautiful and loves beauty.", "narr": "Abdullah ibn Mas'ud", "src": "Muslim", "auth": "Sahih", "cat": "Character"}, {"ar": "الْكَلِمَةُ الطَّيِّبَةُ صَدَقَةٌ", "en": "A good word is charity.", "narr": "Abu Hurairah", "src": "Bukhari & Muslim", "auth": "Sahih", "cat": "Speech"}, {"ar": "مَنْ سَلَكَ طَرِيقًا يَلْتَمِسُ فِيهِ عِلْمًا سَهَّلَ اللَّهُ لَهُ بِهِ طَرِيقًا إِلَى الْجَنَّةِ", "en": "Whoever travels a path seeking knowledge, Allah will make easy for him a path to Paradise.", "narr": "Abu Hurairah", "src": "Muslim", "auth": "Sahih", "cat": "Knowledge"}, {"ar": "مَنْ صَلَّى عَلَيَّ صَلَاةً صَلَّى اللَّهُ عَلَيْهِ بِهَا عَشْرًا", "en": "Whoever sends blessings upon me once, Allah will send blessings upon him tenfold.", "narr": "Abu Hurairah", "src": "Muslim", "auth": "Sahih", "cat": "Worship"}, {"ar": "إِنَّ الصِّدْقَ يَهْدِي إِلَى الْبِرِّ وَإِنَّ الْبِرَّ يَهْدِي إِلَى الْجَنَّةِ", "en": "Truthfulness leads to righteousness, and righteousness leads to Paradise.", "narr": "Abdullah ibn Mas'ud", "src": "Bukhari & Muslim", "auth": "Sahih", "cat": "Character"}, {"ar": "الْمُؤْمِنُ الْقَوِيُّ خَيْرٌ وَأَحَبُّ إِلَى اللَّهِ مِنَ الْمُؤْمِنِ الضَّعِيفِ", "en": "The strong believer is better and more beloved to Allah than the weak believer, though there is good in both.", "narr": "Abu Hurairah", "src": "Muslim", "auth": "Sahih", "cat": "Character"}, {"ar": "لَا يَدْخُلُ الْجَنَّةَ مَنْ كَانَ فِي قَلْبِهِ مِثْقَالُ ذَرَّةٍ مِنْ كِبْرٍ", "en": "No one who has an atom's weight of arrogance in his heart will enter Paradise.", "narr": "Abdullah ibn Mas'ud", "src": "Muslim", "auth": "Sahih", "cat": "Character"}, {"ar": "أَفْضَلُ الصَّدَقَةِ جُهْدُ الْمُقِلِّ", "en": "The best of charity is that given by one who has little.", "narr": "Abu Hurairah", "src": "Abu Dawud", "auth": "Sahih", "cat": "Charity"}, {"ar": "مَنْ سَتَرَ مُسْلِمًا سَتَرَهُ اللَّهُ فِي الدُّنْيَا وَالْآخِرَةِ", "en": "Whoever conceals the faults of a Muslim, Allah will conceal his faults in this world and the next.", "narr": "Abu Hurairah", "src": "Muslim", "auth": "Sahih", "cat": "Brotherhood"}, {"ar": "خَيْرُكُمْ مَنْ تَعَلَّمَ الْقُرْآنَ وَعَلَّمَهُ", "en": "The best of you are those who learn the Qur'an and teach it.", "narr": "Uthman ibn Affan", "src": "Bukhari", "auth": "Sahih", "cat": "Knowledge"}, {"ar": "مَنْ صَامَ رَمَضَانَ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ", "en": "Whoever fasts in Ramadan out of faith and seeking reward, their previous sins are forgiven.", "narr": "Abu Hurairah", "src": "Bukhari & Muslim", "auth": "Sahih", "cat": "Worship"}, {"ar": "اتَّقِ اللَّهَ حَيْثُمَا كُنْتَ", "en": "Fear Allah wherever you are. Follow a bad deed with a good one to erase it, and treat people with good character.", "narr": "Abu Dharr & Mu'adh", "src": "Tirmidhi", "auth": "Hasan", "cat": "Character", "num": 18}, {"ar": "لَا يُؤْمِنُ أَحَدُكُمْ حَتَّى يَكُونَ هَوَاهُ تَبَعًا لِمَا جِئْتُ بِهِ", "en": "None of you truly believes until his desires are in accordance with what I have brought.", "narr": "Abdullah ibn Amr", "src": "Various", "auth": "Hasan", "cat": "Faith", "num": 41}, {"ar": "الْحَيَاءُ مِنَ الْإِيمَانِ", "en": "Modesty is part of faith.", "narr": "Abdullah ibn Umar", "src": "Bukhari & Muslim", "auth": "Sahih", "cat": "Character"}, {"ar": "لَا ضَرَرَ وَلَا ضِرَارَ", "en": "There should be neither harming nor reciprocating harm.", "narr": "Abu Sa'id al-Khudri", "src": "Ibn Majah", "auth": "Hasan", "cat": "Character", "num": 32}, {"ar": "كُلُّ مَعْرُوفٍ صَدَقَةٌ", "en": "Every act of goodness is charity.", "narr": "Jabir", "src": "Bukhari & Muslim", "auth": "Sahih", "cat": "Charity"}, {"ar": "الْجَنَّةُ تَحْتَ أَقْدَامِ الْأُمَّهَاتِ", "en": "Paradise lies beneath the feet of mothers.", "narr": "various", "src": "Nasa'i", "auth": "Sahih", "cat": "Family"}, {"ar": "خَيْرُكُمْ خَيْرُكُمْ لِأَهْلِهِ", "en": "The best of you are those who are best to their families.", "narr": "Aisha", "src": "Tirmidhi", "auth": "Sahih", "cat": "Family"}, {"ar": "مَنْ كَانَ آخِرُ كَلَامِهِ لَا إِلَهَ إِلَّا اللَّهُ دَخَلَ الْجَنَّةَ", "en": "Whoever's last words are 'There is no god but Allah' will enter Paradise.", "narr": "Mu'adh ibn Jabal", "src": "Abu Dawud", "auth": "Sahih", "cat": "Tawheed"}, {"ar": "مَا نَقَصَتْ صَدَقَةٌ مِنْ مَالٍ", "en": "Charity does not decrease wealth.", "narr": "Abu Hurairah", "src": "Muslim", "auth": "Sahih", "cat": "Charity"}, {"ar": "الْجَارُ قَبْلَ الدَّارِ", "en": "The neighbor before the house (consider the neighbor before buying a house).", "narr": "various", "src": "Baghdadi", "auth": "Hasan", "cat": "Brotherhood"}, {"ar": "مَا مَلأَ آدَمِيٌّ وِعَاءً شَرًّا مِنْ بَطْنِهِ", "en": "No human fills a container worse than his stomach. A few morsels to keep his back straight is enough.", "narr": "Miqdam ibn Ma'dikarib", "src": "Tirmidhi", "auth": "Hasan", "cat": "Character"}, {"ar": "لَا تَحْقِرَنَّ مِنَ الْمَعْرُوفِ شَيْئًا", "en": "Do not belittle any act of kindness, even meeting your brother with a cheerful face.", "narr": "Abu Dharr", "src": "Muslim", "auth": "Sahih", "cat": "Character"}, {"ar": "مَنْ دَلَّ عَلَى خَيْرٍ فَلَهُ مِثْلُ أَجْرِ فَاعِلِهِ", "en": "Whoever guides someone to goodness has the same reward as the one who does it.", "narr": "Abu Mas'ud", "src": "Muslim", "auth": "Sahih", "cat": "Character"}, {"ar": "إِنَّ اللَّهَ يُحِبُّ إِذَا عَمِلَ أَحَدُكُمْ عَمَلًا أَنْ يُتْقِنَهُ", "en": "Indeed Allah loves when one of you does a deed, that he perfects it.", "narr": "Aisha", "src": "Al-Bayhaqi", "auth": "Hasan", "cat": "Character"}, {"ar": "طَلَبُ الْعِلْمِ فَرِيضَةٌ عَلَى كُلِّ مُسْلِمٍ", "en": "Seeking knowledge is an obligation upon every Muslim.", "narr": "Anas", "src": "Ibn Majah", "auth": "Hasan", "cat": "Knowledge"}, {"ar": "الْمُؤْمِنُ لِلْمُؤْمِنِ كَالْبُنْيَانِ", "en": "A believer to another believer is like a building — each part strengthens the other.", "narr": "Abu Musa", "src": "Bukhari & Muslim", "auth": "Sahih", "cat": "Brotherhood"}, {"ar": "إِنَّ اللَّهَ لَا يَنْظُرُ إِلَى أَجْسَادِكُمْ", "en": "Allah does not look at your bodies or your appearances, but He looks at your hearts and your deeds.", "narr": "Abu Hurairah", "src": "Muslim", "auth": "Sahih", "cat": "Character"}, {"ar": "مَنْ لَمْ يَرْحَمْ صَغِيرَنَا وَيُوَقِّرْ كَبِيرَنَا فَلَيْسَ مِنَّا", "en": "He is not one of us who does not show mercy to our young and respect to our elders.", "narr": "Ibn Abbas", "src": "Tirmidhi", "auth": "Sahih", "cat": "Family"}, {"ar": "الْحَلَالُ بَيِّنٌ وَالْحَرَامُ بَيِّنٌ", "en": "What is lawful is clear, and what is unlawful is clear, and between them are doubtful matters.", "narr": "An-Nu'man ibn Bashir", "src": "Bukhari & Muslim", "auth": "Sahih", "cat": "Faith", "num": 6}, {"ar": "ازْهَدْ فِي الدُّنْيَا يُحِبَّكَ اللَّهُ", "en": "Be indifferent to the world, and Allah will love you. Be indifferent to what people possess, and people will love you.", "narr": "Sahl ibn Sa'd", "src": "Ibn Majah", "auth": "Hasan", "cat": "Character", "num": 31}];
const STORIES = [{"name": "Adam (AS)", "sub": "The First Human, The First Prophet", "icon": "🌿", "body": "Allah created Adam from clay with His own hands and breathed into him from His spirit. He taught Adam the names of all things — a knowledge even the angels did not possess. When Allah commanded the angels to prostrate to Adam out of honor, all did except Iblis, who refused out of arrogance.\n\nAllah placed Adam and his wife Hawwa (Eve) in Paradise, permitting them to eat from every tree except one. Iblis, consumed with envy, whispered to them until they ate from the forbidden tree. They were sent to earth — but Allah taught Adam words of repentance: 'Our Lord, we have wronged ourselves, and if You do not forgive us and have mercy on us, we shall surely be among the losers.' (7:23) Allah forgave him.", "lesson": "No matter how deeply we fall, sincere repentance wipes the slate clean. Adam's first lesson: when you sin, turn back to Allah."}, {"name": "Nuh (AS)", "sub": "The Patient Warner", "icon": "🛶", "body": "Nuh called his people to worship Allah alone for 950 years. They mocked him, threw stones, plugged their ears. Only a few believed. Allah then commanded Nuh to build an ark in the middle of the desert — the people laughed, but Nuh kept building.\n\nWhen the flood came, the water gushed from the earth and poured from the sky. Nuh boarded the ark with the believers and pairs of every animal. His own son refused to board, saying he would climb a mountain — he drowned. The rain stopped only when Allah commanded: 'O earth, swallow your water, and O sky, withhold.' (11:44)", "lesson": "Consistency in da'wah matters more than results. Nuh preached for nearly a millennium with little success — yet Allah praised him eternally for his perseverance."}, {"name": "Ibrahim (AS)", "sub": "The Friend of Allah (Khalil Allah)", "icon": "🔥", "body": "Ibrahim was born among idol-worshippers, yet from a young age he questioned them. He broke the idols of his people, leaving only the largest, then told them to ask it who did it. They said: 'You know these idols cannot speak!' He replied: 'Then why do you worship what cannot help or harm?'\n\nThey threw him into a massive fire. Allah commanded: 'O fire, be coolness and safety upon Ibrahim.' (21:69) He walked out unharmed. Later, he was tested again — commanded to sacrifice his son Isma'il. Both father and son submitted. At the last moment, Allah sent a ram to be sacrificed instead. This is commemorated in Eid al-Adha.", "lesson": "True tawheed means submitting to Allah even when it defies logic, family, and fire itself. Ibrahim's name is remembered in every salah of every Muslim until the Day of Judgment."}, {"name": "Yusuf (AS)", "sub": "The Most Beautiful Story", "icon": "⭐", "body": "Yusuf was loved by his father Ya'qub above his brothers. Out of jealousy, his brothers threw him into a well. He was picked up by a caravan and sold as a slave in Egypt. There, his master's wife tried to seduce him — he refused, and she had him thrown into prison.\n\nIn prison, Yusuf interpreted dreams. Years later, the king had a dream no one could interpret. Yusuf interpreted it: seven years of plenty followed by seven years of famine. The king made Yusuf the treasurer of Egypt. During the famine, his brothers came seeking food — not recognizing him. When Yusuf revealed himself, he said: 'No blame upon you today. May Allah forgive you.' (12:92)", "lesson": "What looks like the worst thing to happen to you may be the path to your greatest elevation. Trust the process Allah has written for you."}, {"name": "Musa (AS)", "sub": "The One Allah Spoke To (Kaleem Allah)", "icon": "🌊", "body": "Musa was born when Pharaoh was killing all male Israelite children. His mother placed him in a basket in the Nile. He floated right into Pharaoh's palace, where he was raised as a prince. As a young man, he accidentally killed an Egyptian and fled to Madyan, where he worked for eight years before marrying.\n\nOn his way back to Egypt, Allah spoke to him directly at Mount Tur and commanded him to confront Pharaoh. With his staff, he parted the Red Sea for the Israelites to cross. When Pharaoh's army followed, the sea closed over them. Allah saved Pharaoh's body as a sign for those who come after.", "lesson": "Allah can raise the instrument of tyranny's defeat inside the tyrant's own home. No oppressor is beyond Allah's reach."}, {"name": "Isa (AS)", "sub": "The Messiah, Son of Maryam", "icon": "🕊️", "body": "Maryam, the chosen pure woman, was told by the angel Jibreel that she would bear a son without a father. She gave birth to Isa under a palm tree. When she returned to her people with the baby, they accused her of sin. Baby Isa spoke from the cradle: 'Indeed, I am the servant of Allah. He has given me the Scripture and made me a prophet.' (19:30)\n\nIsa performed miracles by Allah's permission: healing the blind and leper, reviving the dead, and creating a bird from clay. When his people sought to kill him, Allah raised him to Himself. He will return before the Day of Judgment to establish justice and kill the Dajjal.", "lesson": "Allah honors the pure. Maryam is the greatest woman ever to have lived. Her son spoke truth from the cradle — truth spoken sincerely is never defeated."}, {"name": "Muhammad ﷺ", "sub": "The Final Messenger, Mercy to the Worlds", "icon": "🌙", "body": "Muhammad ﷺ was born an orphan in Mecca. Known as Al-Amin (The Trustworthy) even before prophethood, he received the first revelation at age 40 in the cave of Hira: 'Read, in the name of your Lord who created.' (96:1)\n\nHe preached for 13 years in Mecca, enduring brutal persecution, boycott, and loss. He migrated to Madinah, where he established the first Muslim community. He never took revenge when entering Mecca victorious — instead saying: 'Go, you are free.' He united Arabia, delivered the farewell sermon, and passed away at age 63 with the words: 'Rather, the Highest Companion.'", "lesson": "The Prophet ﷺ is the perfect example for every believer — how to live, love, lead, forgive, worship, and die. 'Indeed in the Messenger of Allah you have the best example.' (33:21)"}, {"name": "Yunus (AS)", "sub": "Swallowed by the Whale", "icon": "🐋", "body": "Yunus was sent to the people of Nineveh. After years of calling them to Allah with no response, he left in frustration before Allah's permission. He boarded a ship, which was soon caught in a violent storm. The sailors cast lots — Yunus was thrown overboard and a massive whale swallowed him.\n\nIn the darkness of the whale's belly, Yunus called out: 'There is no god but You. Glory be to You. Indeed I have been of the wrongdoers.' (21:87) Allah heard him and ordered the whale to release him on a desolate shore. Allah then caused a plant to grow to shade him until he recovered, and his people — having seen the signs — all believed.", "lesson": "When you are swallowed by your own darkness, remember: no place is beyond Allah's hearing. The du'a of Yunus is perhaps the most powerful prayer for anyone in distress."}, {"name": "Ayyub (AS)", "sub": "The Prophet of Patience", "icon": "⏳", "body": "Ayyub was blessed with wealth, children, and health — yet he never forgot Allah. Allah tested him: he lost his wealth, all his children died, and his body was struck with a painful disease for years. His friends abandoned him. Only his wife remained, working hard to feed him.\n\nThrough all of this, Ayyub never complained once. He only whispered: 'Indeed adversity has touched me, and You are the Most Merciful of the merciful.' (21:83) Allah restored his health, returned his family, and doubled his wealth. His name lives on as the Quranic symbol of patience itself.", "lesson": "Patience in hardship is not the absence of pain — it is refusing to complain against the One who decrees it. Every loss with patience is a gain with Allah."}, {"name": "Sulaiman (AS)", "sub": "The Prophet-King", "icon": "👑", "body": "Sulaiman inherited prophethood and kingship from his father Dawud. Allah gave him unprecedented gifts: he could command the wind, understand the speech of animals and jinn, and ruled a kingdom no one else would be given. Ants, birds, jinn, and humans were all under his authority.\n\nYet with all this power, he remained humble. When he saw his vast army, he didn't boast — he said: 'This is from the favor of my Lord, to test me whether I will be grateful or ungrateful.' (27:40) His greatest wisdom was not his throne but his recognition that every blessing is a test.", "lesson": "Power is the hardest test. The one who has everything and remains humble has truly passed."}, {"name": "Dawud (AS)", "sub": "King, Prophet, Warrior", "icon": "🎵", "body": "Dawud was a young shepherd when he faced the giant Jalut (Goliath) armed only with a sling and his faith. He defeated the giant with a single stone. Allah made him a king after Saul, and gave him a voice so beautiful that mountains and birds would join him in praising Allah. He was given the Zabur (Psalms).\n\nHe was known for his fasting (fasting every other day is called the 'fast of Dawud') and his deep devotion. He would spend nights in prayer despite his kingdom. He judged with justice, and Allah granted him wisdom and strong speech.", "lesson": "The smallest believer armed with truth can bring down the greatest tyrant. Your size does not limit your capability — your faith does."}, {"name": "Zakariyya (AS)", "sub": "The Prayer for a Child", "icon": "🌸", "body": "Zakariyya was the guardian of Maryam. He noticed that Maryam always had out-of-season fruit — Allah was providing for her directly. This rekindled his hope. Though he was very old and his wife was barren, he prayed: 'My Lord, do not leave me alone, though You are the best of inheritors.' (21:89)\n\nAllah answered with a son: Yahya. Zakariyya was told: 'We give you good tidings of a boy whose name is Yahya. We have not assigned to any before him that name.' (19:7)", "lesson": "Never stop asking Allah — even when all logic says 'no'. He is the one who gives fruit out of season and sons out of barrenness."}, {"name": "Yahya (AS)", "sub": "The Gift of the Impossible Prayer", "icon": "📜", "body": "Yahya was the son given to Zakariyya in old age. From childhood, he was granted wisdom: 'O Yahya, take the Scripture with determination.' (19:12) He was devout, obedient to his parents, and never arrogant.\n\nAllah describes him with words He used for no other: pious, kind to his parents, and peace upon him 'the day he was born, the day he dies, and the day he is raised alive.' (19:15) He was eventually martyred for speaking the truth to an oppressive ruler.", "lesson": "True piety is not just worship — it is being kind to parents, gentle to creation, and unafraid to speak truth to power."}, {"name": "Yusuf's Brothers", "sub": "The Lesson of Envy", "icon": "👥", "body": "When the brothers of Yusuf saw their father's love for him, they plotted against their own brother. They threw him in a well and lied to their father — bringing back a shirt stained with fake blood. For decades they lived with this lie while Ya'qub wept until he went blind.\n\nYears later, in famine, they came to Egypt begging for food. They did not recognize Yusuf, but he recognized them. When he revealed himself, they were ashamed. He forgave them: 'No blame upon you today.' (12:92)", "lesson": "Envy destroys families and decades. No amount of honor someone else gets diminishes what Allah has for you. What is yours will never miss you, and what is not yours will never reach you."}, {"name": "Luqman (AS)", "sub": "The Wise", "icon": "💡", "body": "Luqman was not a prophet, but Allah gave him such wisdom that He dedicated a whole surah to his advice. Surah Luqman contains his counsel to his son: 'O my son, do not associate anything with Allah. Indeed, shirk is the greatest wrong.' (31:13)\n\nHe advised his son to establish prayer, enjoin good and forbid evil, be patient in hardship, and never walk the earth in arrogance: 'Indeed, Allah does not love every self-deluded boaster.' (31:18) His words are a masterclass in raising children.", "lesson": "The greatest gift a parent can give a child is not wealth, but wisdom rooted in Allah's remembrance."}, {"name": "Khadija (RA)", "sub": "The First Believer", "icon": "💎", "body": "Khadija was the Prophet's ﷺ first wife, older than him, a successful businesswoman, and the first person to embrace Islam. When the Prophet ﷺ returned from the cave of Hira shaking in fear after the first revelation, she wrapped him in a cloak and said the words every believer should memorize:\n\n'By Allah, Allah will never disgrace you. You keep good relations with your kin, help the poor and the destitute, serve your guests generously, and assist those struck by calamity.' She spent her entire fortune supporting Islam. When she died, it was called 'the Year of Sorrow.'", "lesson": "The right partner is the one who believes in your mission when no one else does. Be a Khadija to someone — or marry one."}, {"name": "The People of the Cave", "sub": "Ashab al-Kahf", "icon": "🕳️", "body": "A group of young believers fled a tyrannical king who forced idol worship. They took refuge in a cave, saying: 'Our Lord, grant us from Yourself mercy and prepare for us from our affair right guidance.' (18:10) Allah caused them to sleep for 309 years.\n\nWhen they awoke, they thought they had slept only a day. They sent one of them to buy food — and his ancient coins revealed that centuries had passed. The society had transformed; their story was now a sign for everyone.", "lesson": "Holding onto your faith in a corrupt society is so beloved to Allah, He preserved these young men for 300 years as a living miracle. When everyone around you loses the truth, you only need to hold onto yours."}, {"name": "Dhul-Qarnayn", "sub": "The Just Conqueror", "icon": "⚔️", "body": "Allah gave Dhul-Qarnayn rulership over the earth — travelling from the far East to the far West. When he reached a people oppressed by the savage tribes of Ya'juj and Ma'juj, they offered him wealth to build a wall.\n\nHe refused the wealth: 'What my Lord has established for me is better.' (18:95) Instead, he asked for their labor and built a wall of iron and molten copper. When done, he said: 'This is a mercy from my Lord.' A ruler who built with the people, not over them.", "lesson": "Real leadership is not extraction — it's protecting the weak with the resources Allah has given you. Use your power to build walls against oppression, not thrones above people."}, {"name": "Asiya (RA)", "sub": "The Believing Wife of Pharaoh", "icon": "🏛️", "body": "Asiya lived inside the palace of the worst tyrant in history — Pharaoh, who claimed to be a god. She was the one who pulled baby Musa from the Nile. Secretly, she believed. When her faith was discovered, Pharaoh tortured her brutally.\n\nAs she died, she prayed: 'My Lord, build for me near You a house in Paradise and save me from Pharaoh and his deeds.' (66:11) Allah answered her. The Prophet ﷺ said she is one of the four perfect women of all time.", "lesson": "Your environment doesn't define you — your choices do. Asiya lived in a palace of oppression but her soul belonged to Paradise. Where you are matters less than who you are."}, {"name": "Maryam (RA)", "sub": "The Chosen One", "icon": "🕊️", "body": "Maryam was dedicated to Allah before she was born. She grew up in the masjid, miraculously provided for. She was so pure that Allah chose her above all women of all worlds: 'O Maryam, indeed Allah has chosen you and purified you.' (3:42)\n\nShe bore Isa miraculously, endured the slander of her people, and raised him alone. She is the only woman named in the Qur'an. An entire surah is named after her.", "lesson": "Allah chooses the pure. Maryam was chosen because her heart was entirely His. Keep your heart clean and Allah may elevate you to places no one imagined."}, {"name": "Hajar (RA)", "sub": "The Mother of Sa'i", "icon": "💧", "body": "Ibrahim, by Allah's command, left his wife Hajar and infant son Isma'il in a barren valley in Mecca. When their water ran out and Isma'il cried with thirst, Hajar ran between the hills of Safa and Marwah seven times searching for water.\n\nAllah then caused the Zamzam spring to gush forth beneath baby Isma'il's foot. This spring has flowed for thousands of years. Every Muslim performing Hajj or Umrah re-enacts Hajar's run — honoring the faith of one desperate mother forever.", "lesson": "Allah doesn't waste your striving. Hajar ran seven times and Allah eternalized her run as a pillar of worship. Your struggle matters — keep running."}, {"name": "Companions of the Trench", "sub": "Ashab al-Ukhdud", "icon": "🔥", "body": "A tyrannical king forced his people to abandon their faith. When a boy showed the power of faith by healing the blind in Allah's name, the king tried everything to kill him. Every plot failed. Finally, the boy said: 'You will never kill me until you say: In the name of Allah, the Lord of the boy.'\n\nThe king did — and the boy died, but everyone who saw it believed. The king, enraged, dug trenches, lit fires, and threw every believer in. A mother holding her nursing baby hesitated. The baby spoke: 'O mother, be patient. You are upon the truth.'", "lesson": "Your death upon faith may do more for Islam than your whole life. And Allah can make even infants speak truth."}, {"name": "Musa and Al-Khidr", "sub": "The Teacher of Hidden Knowledge", "icon": "🔍", "body": "Musa was told there was someone with knowledge he did not have. He travelled until he met Al-Khidr, who agreed to teach him — on condition he ask no questions. Al-Khidr damaged a ship, killed a boy, and rebuilt a wall for free. Musa couldn't stay silent.\n\nWhen they parted, Al-Khidr explained: the ship belonged to poor workers whose tyrant king was seizing ships — he damaged it to save it. The boy would have caused his righteous parents to lose faith. The wall had treasure for orphans. Every act that seemed cruel was mercy.", "lesson": "What you see as a disaster may be Allah's mercy in disguise. Trust that His plan is deeper than your vision."}, {"name": "The Youth and the Angel of Death", "sub": "Trust in Provision", "icon": "🌾", "body": "A man worked hard all day and still could barely feed his family. One night, as he sat exhausted, a voice reminded him: 'The provision of every creature is guaranteed by Allah. Even the worm in the rock, the fish in the deepest sea.' The Prophet ﷺ said: 'If you trusted Allah as you should, He would provide for you as He provides for the birds — they go out empty and return full.'", "lesson": "Anxiety about provision is a sign of weak tawakkul. Work hard, but leave the results to Allah. He has never failed a single creature in history — He will not fail you."}, {"name": "The Three Men in the Cave", "sub": "The Power of Sincere Deeds", "icon": "🗻", "body": "Three men sheltered in a cave. A boulder rolled and sealed the entrance. They agreed each would mention their most sincere deed, hoping Allah would remove it. The first: he refused to harm a woman when he had the chance and power. The second: he paid a worker's wage with interest years later. The third: he honored his aged parents above himself and his children.\n\nWith each sincere deed mentioned, the boulder moved — until they walked out free.", "lesson": "One sincere deed done for Allah alone can save you from impossible situations. Build a private bank of deeds between you and Allah that no one else knows about."}];

